package com.example.demo.ui;import com.example.demo.dto.*;import com.example.demo.services.*;import com.vaadin.flow.component.button.*;import com.vaadin.flow.component.combobox.ComboBox;import com.vaadin.flow.component.dialog.Dialog;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.*;import com.vaadin.flow.component.textfield.*;import com.vaadin.flow.router.*;import java.math.BigDecimal;import java.util.*;
@Route(value="devoluciones",layout=MainLayout.class)@PageTitle("Devoluciones | Franco")public class DevolucionesView extends VerticalLayout{private final DevolucionService service;private final VentaService ventas;private final Grid<DevolucionDTO>grid=new Grid<>(DevolucionDTO.class,false);public DevolucionesView(DevolucionService service,VentaService ventas){this.service=service;this.ventas=ventas;addClassName("content-view");setSizeFull();Button add=new Button("Nueva devolución",e->form());add.addThemeVariants(ButtonVariant.LUMO_PRIMARY);grid.addColumn(DevolucionDTO::fecha).setHeader("Fecha");grid.addColumn(DevolucionDTO::ventaId).setHeader("Venta");grid.addColumn(DevolucionDTO::motivo).setHeader("Motivo");grid.addColumn(DevolucionDTO::total).setHeader("Total");grid.addColumn(DevolucionDTO::formaReintegro).setHeader("Reintegro");add(ViewSupport.header("Devoluciones",add),grid);expand(grid);refresh();}private void refresh(){grid.setItems(service.listar());}private void form(){Dialog d=new Dialog();d.setHeaderTitle("Registrar devolución");d.setWidth("min(800px,95vw)");ComboBox<VentaDTO>sale=new ComboBox<>("Venta");sale.setItems(ventas.listarDTO().stream().filter(v->"CONFIRMADA".equals(v.estado())).toList());sale.setItemLabelGenerator(v->(v.numeroComprobante()==null?"Venta "+v.id():v.numeroComprobante())+" · "+v.total());TextField reason=new TextField("Motivo");ComboBox<String>refund=new ComboBox<>("Forma de reintegro");refund.setItems("EFECTIVO","SALDO_A_FAVOR","SIN_REINTEGRO");refund.setValue("EFECTIVO");VerticalLayout rows=new VerticalLayout();List<Row>values=new ArrayList<>();sale.addValueChangeListener(e->{rows.removeAll();values.clear();if(e.getValue()!=null)e.getValue().items().forEach(i->{BigDecimalField q=new BigDecimalField(i.nombreProducto()+" · máximo "+i.cantidadMostrada());q.setValue(BigDecimal.ZERO);rows.add(q);values.add(new Row(i,q));});});d.add(new VerticalLayout(sale,reason,refund,rows));Button save=new Button("Confirmar",e->{try{if(sale.getValue()==null)throw new IllegalArgumentException("Seleccioná una venta");List<DevolucionCreateDTO.ItemDTO>items=values.stream().filter(x->x.quantity.getValue()!=null&&x.quantity.getValue().signum()>0).map(x->new DevolucionCreateDTO.ItemDTO(x.item.id(),base(x))).toList();if(items.isEmpty())throw new IllegalArgumentException("Indicá al menos una cantidad");service.crear(new DevolucionCreateDTO(sale.getValue().id(),reason.getValue(),refund.getValue(),UserSession.getUser().id(),items));d.close();refresh();ViewSupport.success("Devolución registrada");}catch(RuntimeException ex){ViewSupport.error(ex);}});save.addThemeVariants(ButtonVariant.LUMO_PRIMARY);d.getFooter().add(new Button("Cancelar",e->d.close()),save);d.open();}private int base(Row r){try{return("PESO".equals(r.item.unidadVenta())?r.quantity.getValue().movePointRight(3):r.quantity.getValue()).intValueExact();}catch(ArithmeticException ex){throw new IllegalArgumentException("Cantidad inválida");}}private record Row(ItemVentaDTO item,BigDecimalField quantity){}}
